/// `norm_type` can be the sentinel string `"__Infinity__"` after patching.
fn parse_norm_type(v: &serde_json::Value) -> f64 {
    match v {
        serde_json::Value::Number(n) => n.as_f64().expect("norm_type is a number"),
        serde_json::Value::String(s) if s == "__Infinity__" => f64::INFINITY,
        other => panic!("unexpected norm_type value: {other:?}"),
    }
}

