// ---------------------------------------------------------------------------
// Helper: make a Parameter<f32> with a gradient set
// ---------------------------------------------------------------------------

fn make_param_with_grad(grad_data: &[f64], shape: &[usize]) -> Parameter<f32> {
    let data_f32: Vec<f32> = grad_data.iter().map(|_| 1.0_f32).collect();
    let grad_f32: Vec<f32> = grad_data.iter().map(|&v| v as f32).collect();
    let p = Parameter::from_slice(&data_f32, shape).unwrap();
    let g = Tensor::from_storage(TensorStorage::cpu(grad_f32), shape.to_vec(), false).unwrap();
    p.set_grad(Some(g)).unwrap();
    p
}

/// Minimal pass-through scaling module for checkpoint_sequential tests.
struct ScaleModule {
    factor: f32,
}

impl ferrotorch_nn::Module<f32> for ScaleModule {
    fn forward(&self, input: &Tensor<f32>) -> ferrotorch_core::FerrotorchResult<Tensor<f32>> {
        let s = ferrotorch_core::scalar(self.factor)?;
        ferrotorch_core::grad_fns::arithmetic::mul(input, &s)
    }

    fn parameters(&self) -> Vec<&Parameter<f32>> {
        vec![]
    }
    fn parameters_mut(&mut self) -> Vec<&mut Parameter<f32>> {
        vec![]
    }
    fn named_parameters(&self) -> Vec<(String, &Parameter<f32>)> {
        vec![]
    }
    fn train(&mut self) { /* stateless test module — no training/eval mode to toggle */
    }
    fn eval(&mut self) { /* stateless test module — no training/eval mode to toggle */
    }
    fn is_training(&self) -> bool {
        true
    }
}

