#[test]
fn fixture_file_has_all_sections() {
    let file = load_fixtures();
    eprintln!(
        "  fixture_file_has_all_sections: torch={}, {} metric fixtures, {} grad_utils, {} ema, \
         {} history, {} early_stopping, {} grad_accum, {} checkpoint_sequential, {} amp",
        file.metadata.torch_version,
        file.metric.len(),
        file.grad_utils.len(),
        file.ema.len(),
        file.history.len(),
        file.early_stopping.len(),
        file.grad_accum.len(),
        file.checkpoint_sequential.len(),
        file.amp.len(),
    );
    assert!(!file.metric.is_empty(), "metric section is empty");
    assert!(!file.grad_utils.is_empty(), "grad_utils section is empty");
    assert!(!file.ema.is_empty(), "ema section is empty");
    assert!(!file.history.is_empty(), "history section is empty");
    assert!(
        !file.early_stopping.is_empty(),
        "early_stopping section is empty"
    );
    assert!(!file.grad_accum.is_empty(), "grad_accum section is empty");
    assert!(
        !file.checkpoint_sequential.is_empty(),
        "checkpoint_sequential section is empty"
    );
    assert!(!file.amp.is_empty(), "amp section is empty");
}

