/// LossMetric::update and compute accumulate to the correct mean.
#[test]
fn loss_metric_basic_mean() {
    let file = load_fixtures();
    let f = file
        .metric
        .iter()
        .find(|m| matches!(m, MetricFixture::LossMetric { .. }))
        .expect("LossMetric basic fixture not found");
    let MetricFixture::LossMetric {
        batches,
        expected_mean,
        label,
    } = f
    else {
        unreachable!()
    };

    let mut m = LossMetric::new();
    for v in batches {
        m.update(v);
    }
    let got = m.compute();
    assert!(
        (got - expected_mean).abs() < 1e-9,
        "[{label}] LossMetric::compute: expected {expected_mean}, got {got}"
    );
}

