/// LossMetric::reset clears accumulated state.
#[test]
fn loss_metric_reset_then_accumulate() {
    let file = load_fixtures();
    let f = file
        .metric
        .iter()
        .find(|m| matches!(m, MetricFixture::LossMetricAfterReset { .. }))
        .expect("LossMetricAfterReset fixture not found");
    let MetricFixture::LossMetricAfterReset {
        batches_before_reset,
        batches_after_reset,
        expected_mean_before,
        expected_mean_after,
        label,
    } = f
    else {
        unreachable!()
    };

    let mut m = LossMetric::new();
    for v in batches_before_reset {
        m.update(v);
    }
    assert!(
        (m.compute() - expected_mean_before).abs() < 1e-9,
        "[{label}] before reset: expected {expected_mean_before}, got {}",
        m.compute()
    );
    m.reset();
    for v in batches_after_reset {
        m.update(v);
    }
    let got = m.compute();
    assert!(
        (got - expected_mean_after).abs() < 1e-9,
        "[{label}] after reset: expected {expected_mean_after}, got {got}"
    );
}

