/// RunningAverage evicts old values correctly.
#[test]
fn running_average_window_eviction() {
    let file = load_fixtures();
    let f = file
        .metric
        .iter()
        .find(|m| matches!(m, MetricFixture::RunningAverage { .. }))
        .expect("RunningAverage fixture not found");
    let MetricFixture::RunningAverage {
        window_size,
        values,
        expected_after_all,
        expected_after_3,
        label,
    } = f
    else {
        unreachable!()
    };

    let mut m = RunningAverage::new(*window_size);
    assert_eq!(m.window_size(), *window_size);

    // Feed first 3 values.
    for v in values.iter().take(3) {
        m.update(v);
    }
    let got3 = m.compute();
    assert!(
        (got3 - expected_after_3).abs() < 1e-9,
        "[{label}] after 3 values: expected {expected_after_3}, got {got3}"
    );

    // Feed the remaining values.
    for v in values.iter().skip(3) {
        m.update(v);
    }
    let got_all = m.compute();
    assert!(
        (got_all - expected_after_all).abs() < 1e-9,
        "[{label}] after all values: expected {expected_after_all}, got {got_all}"
    );
}

// ---------------------------------------------------------------------------
// grad_utils — clip_grad_norm_
// ---------------------------------------------------------------------------

/// For each grad_utils fixture of clip_grad_norm_* kind, validate the total
/// norm and clipped gradient values.
#[test]
fn clip_grad_norm_all_fixtures() {
    let file = load_fixtures();

    for f in &file.grad_utils {
        if !f.kind.starts_with("clip_grad_norm_") {
            continue;
        }
        let label = &f.label;
        let max_norm = f
            .max_norm
            .expect("clip_grad_norm_ fixture must have max_norm");
        let raw_norm_type = f
            .norm_type
            .as_ref()
            .expect("clip_grad_norm_ fixture must have norm_type");
        let norm_type = parse_norm_type(raw_norm_type);

        // Build parameters from fixture grads.
        let params_owned: Vec<Parameter<f32>> = f
            .grads
            .iter()
            .map(|g| make_param_with_grad(g, &[g.len()]))
            .collect();
        let params_ref: Vec<&Parameter<f32>> = params_owned.iter().collect();

        let total_norm = clip_grad_norm_(&params_ref, max_norm, norm_type)
            .unwrap_or_else(|e| panic!("[{label}] clip_grad_norm_ error: {e}"));

        if let Some(expected_norm) = f.expected_total_norm {
            assert!(
                (total_norm - expected_norm).abs() < 1e-4,
                "[{label}] total_norm: expected {expected_norm}, got {total_norm}"
            );
        }

        // Validate clipped values.
        for (i, (param, expected_g)) in params_owned
            .iter()
            .zip(f.expected_clipped.iter())
            .enumerate()
        {
            let grad = param
                .grad()
                .unwrap()
                .expect("param should have grad after clipping");
            let data = grad.data().unwrap();
            assert_eq!(
                data.len(),
                expected_g.len(),
                "[{label}] param[{i}] grad length mismatch"
            );
            for (j, (&got, &exp)) in data.iter().zip(expected_g.iter()).enumerate() {
                assert!(
                    (got as f64 - exp).abs() < 1e-4,
                    "[{label}] param[{i}][{j}]: expected {exp}, got {got}"
                );
            }
        }
    }
}

