fn make_epoch_result(epoch: usize, train_loss: f64, val_loss: Option<f64>) -> EpochResult {
    EpochResult::new_with_defaults(epoch, train_loss, val_loss, 0.001)
}

fn build_history(epochs: &[HistoryEpoch]) -> TrainingHistory {
    let mut h = TrainingHistory::new();
    for e in epochs {
        h.push(make_epoch_result(e.epoch, e.train_loss, e.val_loss));
    }
    h
}

